import {pool} from '../infra/pg';
import {io} from '../server';
import {Chess} from 'chess.js';
export async function move(gameId:number,userId:number,uci:string){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const g=await client.query('SELECT * FROM chess_games WHERE id=$1 FOR UPDATE',[gameId]);
    const isWhite=Number(g.rows[0].white)===userId;
    if((g.rows[0].turn==='w')!==isWhite){await client.query('ROLLBACK');return {error:'not_your_turn'};}
    // clock
    const elapsed=Date.now()-new Date(g.rows[0].clock_started_at).getTime();
    const newClock=Math.max(0,(isWhite?g.rows[0].white_clock_ms:g.rows[0].black_clock_ms)-elapsed);
    if(newClock===0){await client.query("UPDATE chess_games SET status='timeout' WHERE id=$1",[gameId]);await client.query('ROLLBACK');return {error:'timeout'};}
    const ch=new Chess(g.rows[0].fen);
    try{ch.move(uci);}catch{await client.query('ROLLBACK');return {error:'illegal'};}
    const newTurn=g.rows[0].turn==='w'?'b':'w';
    const clockCol=isWhite?'white_clock_ms':'black_clock_ms';
    await client.query(`UPDATE chess_games SET fen=$1,turn=$2,${clockCol}=$3,clock_started_at=now() WHERE id=$4`,[ch.fen(),newTurn,newClock,gameId]);
    await client.query('INSERT INTO chess_moves(game_id,uci) VALUES ($1,$2)',[gameId,uci]);
    if(ch.isGameOver()){await client.query("UPDATE chess_games SET status='ended' WHERE id=$1",[gameId]);}
    await client.query('COMMIT');
    io.of('/chess').to(`game:${gameId}`).emit('state',{fen:ch.fen(),turn:newTurn,lastMove:uci});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
export function registerChessNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('game:join',async({gameId}:any,ack:any)=>{await socket.join(`game:${gameId}`);const g=await pool.query('SELECT * FROM chess_games WHERE id=$1',[gameId]);ack({game:g.rows[0]});});
    socket.on('move',async({gameId,uci}:any,ack:any)=>{const r=await move(gameId,socket.data.user.id,uci);ack(r);});
  });
}

