import { io } from '../server';
async function verifyCaptcha(token: string, ip: string): Promise<boolean> { /* server-side CAPTCHA provider call */ return Boolean(token && ip); }
export async function admitRandom(showId: number) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const inv = await client.query('SELECT inventory FROM shows WHERE id=$1 FOR UPDATE', [showId]);
    const r = await client.query('SELECT id,user_id FROM waiters WHERE show_id=$1 AND admitted_at IS NULL ORDER BY random() LIMIT $2 FOR UPDATE SKIP LOCKED', [showId, Math.min(100, inv.rows[0].inventory)]);
    for (const w of r.rows) {
      await client.query('UPDATE waiters SET admitted_at=now() WHERE id=$1', [w.id]);
      await client.query('INSERT INTO holds(show_id,user_id,expires_at) VALUES ($1,$2,now()+interval '10 minutes') ON CONFLICT (show_id,user_id) DO NOTHING', [showId, w.user_id]);
      io.of('/drop').to(`user:${w.user_id}`).emit('admit', { showId: String(showId), expiresAt: Date.now() + 10 * 60 * 1000 });
    }
    await client.query('UPDATE shows SET inventory=GREATEST(0, inventory-$1) WHERE id=$2', [r.rows.length, showId]);
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}
export function registerDropNamespace(nsp: any) {
  nsp.use(authMw);
