    const uid = socket.data.user.id;
    socket.join(`user:${uid}`);
    socket.on('wait:join', async ({ showId, captchaToken }: any, ack: any) => {
      if (!(await verifyCaptcha(captchaToken, socket.handshake.address))) return ack({ error: 'captcha_required' });
      const r = await pool.query('INSERT INTO waiters(show_id,user_id) VALUES ($1,$2) ON CONFLICT (show_id,user_id) DO UPDATE SET updated_at=now() RETURNING id', [showId, uid]);
      await socket.join(`show:${showId}`);
      ack({ ok: true, waiterId: String(r.rows[0].id) });
    });
  });
}
