import { pool } from '../infra/pg';
import { io } from '../server';
import Anthropic from '@anthropic-ai/sdk';
import { z } from 'zod';
const anth = new Anthropic();
const SendSchema = z.object({ channelId: z.coerce.number().int().positive(), body: z.string().trim().min(1).max(4000) });
const AppealSchema = z.object({ messageId: z.coerce.number().int().positive(), reason: z.string().trim().min(10).max(1000) });
async function isMember(userId: number, channelId: number): Promise<boolean> { const r = await pool.query('SELECT 1 FROM mod_channel_members WHERE channel_id=$1 AND user_id=$2', [channelId, userId]); return r.rowCount > 0; }
async function moderate(body: string): Promise<{ score: number; categories: string[]; unavailable?: boolean }> {
  try {
    const r = await anth.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 80, messages: [{ role: 'user', content: `Rate 0-1 toxicity, categories. JSON only.
${body}` }] });
    return JSON.parse((r.content[0] as any).text);
  } catch { return { score: 1, categories: ['moderation_unavailable'], unavailable: true }; }
}
export async function sendMsg(channelId: number, senderId: number, body: string) {
  if (!(await isMember(senderId, channelId))) return { error: 'forbidden' };
  const mod = await moderate(body);
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const r = await client.query('INSERT INTO mod_messages(channel_id,sender_id,body,severity,review_status) VALUES ($1,$2,$3,$4,$5) RETURNING id', [channelId, senderId, body, mod.score, mod.unavailable ? 'queued' : 'scored']);
    if (mod.unavailable || mod.score > 0.85) {
      await client.query('UPDATE mod_messages SET deleted_at=now(), deletion_reason=$1 WHERE id=$2', [mod.categories.join(','), r.rows[0].id]);
      await client.query('COMMIT');
      io.of('/modchat').to(`chan:${channelId}`).emit('msg:deleted', { messageId: String(r.rows[0].id), reason: mod.unavailable ? 'pending_review' : 'auto_moderated' });
      return { deleted: true, messageId: String(r.rows[0].id) };
    }
    await client.query('COMMIT');
    io.of('/modchat').to(`chan:${channelId}`).emit('msg:new', { id: String(r.rows[0].id), senderId: String(senderId), body });
    return { ok: true };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}
export function registerModchatNamespace(nsp: any) {
  nsp.use(authMw);
  nsp.on('connection', (socket: any) => {
    socket.on('msg:send', async (raw: unknown, ack: any) => { const p = SendSchema.safeParse(raw); ack(p.success ? await sendMsg(p.data.channelId, socket.data.user.id, p.data.body) : { error: 'bad_message' }); });
    socket.on('appeal', async (raw: unknown, ack: any) => { const p = AppealSchema.safeParse(raw); if (!p.success) return ack({ error: 'bad_appeal' }); await pool.query("INSERT INTO mod_appeals(message_id,user_id,reason,status) VALUES ($1,$2,$3,'pending')", [p.data.messageId, socket.data.user.id, p.data.reason]); ack({ ok: true }); });
  });
}

